const allItems = $input.all();
const today = new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric', year: 'numeric' });

// Sort by priority (extract from text if available)
let digest = `<div style='font-family: Georgia, serif; max-width: 700px; padding: 24px; background: #080808; color: #ede9e1;'>`;
digest += `<div style='border-bottom: 1px solid rgba(201,169,110,0.3); padding-bottom: 16px; margin-bottom: 24px;'>`;
digest += `<div style='font-family: monospace; font-size: 11px; letter-spacing: 3px; text-transform: uppercase; color: #c9a96e; margin-bottom: 8px;'>SmartPM Market Intelligence</div>`;
digest += `<h2 style='font-size: 22px; font-weight: 600; color: #ede9e1; margin: 0;'>Weekly Prospect Briefing</h2>`;
digest += `<p style='font-size: 12px; color: #666; margin: 6px 0 0;'>${today} · ${allItems.length} prospects analyzed · Exsto Cura Consilium</p></div>`;

allItems.forEach((item, i) => {
  const p = item.json;
  const signalColor = p.signal === 'LOSS' ? '#e07070' : p.signal === 'DELAY' ? '#e0b870' : '#7dc89a';
  const fitColor = p.smartpm_fit === 'HIGH' ? '#7dc89a' : p.smartpm_fit === 'MEDIUM' ? '#e0b870' : '#888';

  digest += `<div style='margin-bottom: 28px; padding: 18px; background: #111; border-left: 3px solid #c9a96e;'>`;
  digest += `<div style='display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 10px; flex-wrap: wrap; gap: 8px;'>`;
  digest += `<h3 style='font-size: 15px; font-weight: 600; color: #ede9e1; margin: 0;'>${p.company}</h3>`;
  digest += `<div style='display: flex; gap: 6px; flex-wrap: wrap;'>`;
  digest += `<span style='font-size: 10px; padding: 2px 8px; background: rgba(201,169,110,0.1); border: 1px solid rgba(201,169,110,0.3); color: #c9a96e; font-family: monospace; letter-spacing: 1px;'>${p.segment}</span>`;
  digest += `<span style='font-size: 10px; padding: 2px 8px; border: 1px solid; color: ${signalColor}; border-color: ${signalColor}; font-family: monospace; letter-spacing: 1px;'>⚡ ${p.signal}</span>`;
  digest += `<span style='font-size: 10px; padding: 2px 8px; border: 1px solid; color: ${fitColor}; border-color: ${fitColor}; font-family: monospace; letter-spacing: 1px;'>SPM ${p.smartpm_fit}</span>`;
  digest += `</div></div>`;
  digest += `<p style='font-size: 12px; color: #888; margin: 0 0 10px; font-style: italic;'>${p.vertical} · ${p.hq} · ${p.project_range}</p>`;
  digest += `<p style='font-size: 12px; color: #aaa; line-height: 1.6; margin: 0 0 10px;'><strong style='color: #c9a96e;'>Signal:</strong> ${p.signal_detail}</p>`;
  digest += `<p style='font-size: 12px; color: #aaa; line-height: 1.6; margin: 0;'><strong style='color: #c9a96e;'>Your Angle:</strong> ${p.outreach_angle}</p>`;
  if (p.text) {
    const preview = p.text.substring(0, 300);
    digest += `<div style='margin-top: 12px; padding: 10px; background: #1a1a1a; border-top: 1px solid rgba(201,169,110,0.15); font-size: 11px; color: #777; line-height: 1.55;'>${preview}...</div>`;
  }
  digest += `</div>`;
});

digest += `<div style='border-top: 1px solid rgba(201,169,110,0.2); padding-top: 14px; margin-top: 8px;'>`;
digest += `<p style='font-size: 11px; color: #555; font-family: monospace;'>Full briefings with outreach messages saved in Notion BD workspace · Exsto Cura SmartPM Market Agent</p></div></div>`;

return [{ json: { digest, count: allItems.length, date: today } }];
